Period = 12;
SigPeriod =5;

// 1. VWAP 계산식
A = Sum((H+L+C)/3 * V);
B = Sum(V);
D_VWAP = (A - ValueWhen(1, Date(1) != Date, A(1))) / (B - ValueWhen(1, Date(1) != Date, B(1)));

// 2. TRIX 계산식 (12, 5 기준)
T = TRIX(Period);
S = avg(T, SigPeriod);

// 3. 필터 조건 : 주가가 VWAP 위(C > D_VWAP)이면서 TRIX가 골든크로스날 때
C > D_VWAP && CrossUp(T, S)
